// ── Helpers ───────────────────────────────────────────────────────────────────
export function getServicoNacionalByCodigo(codigo: string): ServicoNacionalItem | undefined {
    const c = codigo.replace(/\D/g, '').padStart(6, '0');
    return SERVICO_NACIONAL_OPTIONS.find(s => s.codigo === c);
}

export function getRegraIncidenciaByServico(codigo: string): { lp: boolean; ep: boolean; et: boolean; obra: boolean } {
    const s = getServicoNacionalByCodigo(codigo);
    return { lp: !!s?.lp, ep: !!s?.ep, et: !!s?.et, obra: !!s?.obra };
}

export function getMunicipioByCodigo(value: string): MunicipioItem | undefined {
    const clean = value.trim();
    return MUNICIPIO_OPTIONS.find(
        m => m.codigo === clean || m.value === clean ||
            m.municipio.toLowerCase() === clean.toLowerCase(),
    );
}

export function getNbsByCodigo(raw: string): NbsItem | undefined {
    const digits = raw.replace(/\D/g, '');
    if (!digits) return undefined;
    return NBS_OPTIONS.find(n => n.codigo.replace(/\D/g, '') === digits || n.value === raw || n.codigo === raw);
}

export function getIndopByCodigo(codigo: string): NfseOption | undefined {
    const c = codigo.replace(/\D/g, '').padStart(6, '0');
    return INDOP_OPTIONS.find(i => i.value === c);
}

export function onlyCodigo(value: string): string {
    if (!value) return '';
    return value.trim().split(/\s/)[0];
}

